const { regular, bold, script, icons } = await loadFonts();
  const { name, phone, address, logo } = brandData;
  const scale = getScale(width, height);

  const paint = Skia.Paint();

  // Bottom Gradient Overlay
  const colors = [Skia.Color('transparent'), Skia.Color('rgba(220, 38, 38, 0.95)')]; // Red gradient
  paint.setShader(Skia.Shader.MakeLinearGradient({ x: 0, y: height - 400 * scale }, { x: 0, y: height }, colors, [0, 1], 0));
  canvas.drawRect({ x: 0, y: height - 400 * scale, width, height: 400 * scale }, paint);
  paint.setShader(null);

  // Brand Name in beautiful script
  paint.setColor(Skia.Color('white'));
  const titleFont = script;
  titleFont.setSize(80 * scale);
  drawTextCentered(canvas, name, height - 160 * scale, titleFont, paint, width);

  // Divider Line
  paint.setColor(Skia.Color('rgba(255, 255, 255, 0.5)'));
  canvas.drawRect({ x: width * 0.2, y: height - 130 * scale, width: width * 0.6, height: 2 * scale }, paint);

  // Info Text
  paint.setColor(Skia.Color('white'));
  const infoFont = regular;
  infoFont.setSize(24 * scale);
  const infoText = `${phone}  •  ${address}`;
  drawTextCentered(canvas, infoText, height - 80 * scale, infoFont, paint, width);

  // Circular "Delicious" Badge (Top Right)
  const cx = width - 120 * scale;
  const cy = 120 * scale;
  const r = 80 * scale;

  paint.setColor(Skia.Color('#FBBF24')); // Amber
  canvas.drawCircle(cx, cy, r, paint);

  paint.setStyle(1); // Stroke
  paint.setStrokeWidth(3 * scale);
  paint.setColor(Skia.Color('white'));
  // Skia Path effect for dashed lines isn't available directly in JS without PathEffect.MakeDash,
  // We'll just draw a solid inner ring for now.
  canvas.drawCircle(cx, cy, r - 10 * scale, paint);

  paint.setStyle(0); // Fill
  const badgeFont = bold;
  badgeFont.setSize(22 * scale);
  drawTextCentered(canvas, "100%", cy - 10 * scale, badgeFont, paint, width, r * 2, cx - r);
  drawTextCentered(canvas, "FRESH", cy + 20 * scale, badgeFont, paint, width, r * 2, cx - r);

  return ["phone", "address"];

const { regular, bold, icons, condensed } = await loadFonts();
  const { name, slogan, website, logo } = brandData;
  const scale = getScale(width, height);

  const paint = Skia.Paint();

  // Fresh Green Top Banner
  const topH = 150 * scale;
  paint.setColor(Skia.Color('#4ADE80')); // Green 400
  canvas.drawRect({ x: 0, y: 0, width, height: topH }, paint);

  paint.setColor(Skia.Color('white'));
  const tagFont = condensed;
  tagFont.setSize(40 * scale);
  drawTextCentered(canvas, "100% ORGANIC & NATURAL", 95 * scale, tagFont, paint, width);

  // Glassmorphism Bottom Card
  const cardH = 250 * scale;
  const cardY = height - cardH - 40 * scale;
  const cardX = 40 * scale;
  const cardW = width - 80 * scale;

  paint.setColor(Skia.Color('rgba(255, 255, 255, 0.85)')); // Semi-transparent white
  canvas.drawRRect(Skia.RRectXY({ x: cardX, y: cardY, width: cardW, height: cardH }, 30 * scale, 30 * scale), paint);

  // Brand Name
  paint.setColor(Skia.Color('#166534')); // Dark Green
  const nameFont = bold;
  nameFont.setSize(45 * scale);
  drawTextCentered(canvas, name.toUpperCase(), cardY + 80 * scale, nameFont, paint, width);

  // Slogan
  paint.setColor(Skia.Color('#15803D'));
  const sloganFont = regular;
  sloganFont.setSize(24 * scale);
  if (slogan) drawTextCentered(canvas, slogan, cardY + 130 * scale, sloganFont, paint, width);

  // Website
  if (website) {
    paint.setColor(Skia.Color('#FFFFFF'));
    canvas.drawRRect(Skia.RRectXY({ x: cardX + 50 * scale, y: cardY + 160 * scale, width: cardW - 100 * scale, height: 60 * scale }, 15 * scale, 15 * scale), paint);
    paint.setColor(Skia.Color('#166534'));
    const webFont = bold;
    webFont.setSize(22 * scale);
    drawTextCentered(canvas, website, cardY + 200 * scale, webFont, paint, width);
  }

  // Floating Logo Above Card
  if (logo) {
    const lSize = 120 * scale;
    const lX = (width - lSize) / 2;
    const lY = cardY - (lSize / 2);

    // Draw white background circle for logo
    paint.setColor(Skia.Color('white'));
    canvas.drawCircle(lX + lSize / 2, lY + lSize / 2, (lSize / 2) + 10 * scale, paint);

    const { width: lW, height: lH } = getLogoDimensions(logo);
    drawLogo(canvas, logo, lX, lY, lSize, lSize * (lH / lW));
  }

  return ["website", "slogan", "logoUri"];

