const { serif, classic, regular } = await loadFonts();
  const { name, slogan, website, logo } = brandData;
  const scale = getScale(width, height);

  const paint = Skia.Paint();

  // 1. Thin Gold Border around entire canvas
  paint.setColor(Skia.Color('#D4AF37')); // Gold
  paint.setStyle(1); // Stroke
  paint.setStrokeWidth(2 * scale);
  canvas.drawRect({ x: 20 * scale, y: 20 * scale, width: width - 40 * scale, height: height - 40 * scale }, paint);
  canvas.drawRect({ x: 30 * scale, y: 30 * scale, width: width - 60 * scale, height: height - 60 * scale }, paint);

  // 2. Translucent Center Box
  paint.setStyle(0); // Fill
  paint.setColor(Skia.Color('rgba(0, 0, 0, 0.75)')); // Dark grey translucent
  const boxW = width * 0.85;
  const boxH = 400 * scale;
  const boxX = (width - boxW) / 2;
  const boxY = (height - boxH) / 2;
  canvas.drawRect({ x: boxX, y: boxY, width: boxW, height: boxH }, paint);

  // 3. Logo
  if (logo) {
    const lSize = 90 * scale;
    const lX = (width - lSize) / 2;
    const lY = boxY + 40 * scale;
    const { width: lW, height: lH } = getLogoDimensions(logo);
    drawLogo(canvas, logo, lX, lY, lSize, lSize * (lH / lW));
  }

  // 4. Name
  paint.setColor(Skia.Color('#D4AF37')); // Gold
  const nameFont = classic;
  nameFont.setSize(45 * scale);
  drawTextCentered(canvas, name.toUpperCase(), boxY + 190 * scale, nameFont, paint, width);

  // 5. Divider
  paint.setColor(Skia.Color('rgba(212, 175, 55, 0.4)')); // Faded Gold
  canvas.drawRect({ x: width * 0.3, y: boxY + 220 * scale, width: width * 0.4, height: 1 * scale }, paint);

  // 6. Slogan
  paint.setColor(Skia.Color('white'));
  const sloganFont = serif;
  sloganFont.setSize(24 * scale);
  drawTextCentered(canvas, slogan, boxY + 270 * scale, sloganFont, paint, width);

  // 7. Website (Footer of box)
  paint.setColor(Skia.Color('#D4AF37'));
  const webFont = regular;
  webFont.setSize(18 * scale);
  // Add letter spacing by spacing out the letters manually or just using regular text
  drawTextCentered(canvas, website.toUpperCase(), boxY + 350 * scale, webFont, paint, width);

  return ["slogan", "website", "logoUri"];
